        derived_key = fernet.encrypt(provider_name.encode())
        return derived_key


class EncryptionManager:
    def __init__(self, provider_name):
        self.provider_name = provider_name
        self.provider_class = settings.PROVIDER_REGISTRY[provider_name]
        self.provider_instance = self._get_provider_instance()

    def _get_provider_instance(self):
        module_path, class_name = self.provider_class.rsplit('.', 1)
        module = __import__(module_path, fromlist=[class_name])
        class_ = getattr(module, class_name)
        return class_()

    def encrypt(self, data):
        return self.provider_instance.encrypt(data)


class DecryptionManager:
    def __init__(self, provider_name):
        self.provider_name = provider_name
        self.provider_class = settings.PROVIDER_REGISTRY[provider_name]
        self.provider_instance = self._get_provider_instance()

    def _get_provider_instance(self):
        module_path, class_name = self.provider_class.rsplit('.', 1)
        module = __import__(module_path, fromlist=[class_name])
        class_ = getattr(module, class_name)
